INSERT INTO public.categories (id,name,slug,description,image,created_at,updated_at) VALUES ('d024d42a-8cd3-4eba-8903-b83a6d375b72','Autoconhecimento','autoconhecimento','Descubra quem você realmente é. Artigos sobre introspecção, identidade e jornada interior.','https://gbtobvijtqaaubftmhhl.supabase.co/storage/v1/object/public/cms-images/categories/autoconhecimento.jpg','2026-04-15T21:55:49.029581+00:00','2026-04-15T22:09:33.155253+00:00');
