INSERT INTO public.categories (id,name,slug,description,image,created_at,updated_at) VALUES ('26904ab5-e1aa-4088-95ef-4b3b5f0fd999','Desenvolvimento Pessoal','desenvolvimento-pessoal','Ferramentas e insights para crescer, evoluir e alcançar seu potencial.','https://gbtobvijtqaaubftmhhl.supabase.co/storage/v1/object/public/cms-images/categories/desenvolvimento.jpg','2026-04-15T21:55:49.029581+00:00','2026-04-15T22:09:33.155253+00:00');
INSERT INTO public.posts (id,title,slug,excerpt,content,image,category_id,author,read_time,published,date,created_at,updated_at) VALUES ('59c27075-317e-4963-a857-fdad05162bdb','O poder de se conhecer: por onde começar a jornada interior','o-poder-de-se-conhecer','A jornada do autoconhecimento não exige destino, apenas coragem para olhar para dentro.','<h2>Por que o autoconhecimento importa?</h2>
<p>Vivemos em um mundo que nos ensina a olhar para fora — comparando, competindo, buscando validação. Mas a verdadeira transformação começa quando invertemos essa direção.</p>

<h3>Os primeiros passos</h3>
<p><strong>1. Observe sem julgar.</strong> Comece percebendo seus pensamentos ao longo do dia. Não tente mudá-los, apenas note.</p>
<p><strong>2. Pergunte-se "por quê?" com mais frequência.</strong> Quando sentir uma emoção forte, pause e investigue: de onde isso vem?</p>
<p><strong>3. Escreva.</strong> O diário é uma das ferramentas mais poderosas de autoconhecimento. Não precisa ser perfeito — precisa ser honesto.</p>

<h3>A coragem de ser vulnerável</h3>
<p>Conhecer a si mesmo exige vulnerabilidade. É permitir-se ver as sombras sem fugir delas. Como disse Carl Jung: <em>"Quem olha para fora, sonha; quem olha para dentro, desperta."</em></p>

<blockquote>O autoconhecimento não é um destino. É uma caminhada diária, feita de pequenas pausas e grandes revelações.</blockquote>

<p>A cada dia que você escolhe se observar com gentileza, você se aproxima de quem realmente é.</p>','https://gbtobvijtqaaubftmhhl.supabase.co/storage/v1/object/public/cms-images/posts/autoconhecimento.jpg','d024d42a-8cd3-4eba-8903-b83a6d375b72','Dra. Ana Silva','6 min',TRUE,'2025-04-10T00:00:00+00:00','2026-04-15T21:57:25.836978+00:00','2026-04-15T22:14:52.882481+00:00');
INSERT INTO public.posts (id,title,slug,excerpt,content,image,category_id,author,read_time,published,date,created_at,updated_at) VALUES ('9f534bda-d3d4-4409-ba1a-3e812d741c18','5 sinais de que você precisa cuidar da sua saúde mental','5-sinais-saude-mental','Reconhecer os sinais é o primeiro passo para buscar ajuda e retomar o equilíbrio emocional.','<h2>Ouvindo o que o corpo e a mente dizem</h2>
<p>Muitas vezes ignoramos os sinais que nosso corpo e mente nos enviam. Aqui estão cinco alertas importantes:</p>

<h3>1. Cansaço que não passa com descanso</h3>
<p>Se mesmo após dormir você acorda exausto, pode ser mais do que cansaço físico. O esgotamento emocional se manifesta no corpo.</p>

<h3>2. Irritabilidade constante</h3>
<p>Quando pequenas coisas se tornam grandes problemas, é hora de parar e investigar o que está por trás dessa reatividade.</p>

<h3>3. Isolamento social</h3>
<p>Afastar-se de pessoas queridas pode ser um mecanismo de defesa, mas também um sinal de que algo precisa de atenção.</p>

<h3>4. Dificuldade de concentração</h3>
<p>A mente sobrecarregada não consegue focar. Se você relê o mesmo parágrafo várias vezes, seu cérebro está pedindo uma pausa.</p>

<h3>5. Perda de prazer em atividades que antes eram agradáveis</h3>
<p>Este é um dos sinais mais importantes. Quando nada mais parece interessante, buscar ajuda profissional é fundamental.</p>

<blockquote>Cuidar da saúde mental não é fraqueza — é um ato de coragem e amor-próprio.</blockquote>','https://gbtobvijtqaaubftmhhl.supabase.co/storage/v1/object/public/cms-images/posts/saude-mental.jpg','e1b8865f-2e0c-407d-ba87-fa9721a18b9e','Dra. Ana Silva','5 min',TRUE,'2025-04-08T00:00:00+00:00','2026-04-15T21:57:25.836978+00:00','2026-04-15T22:14:52.882481+00:00');
INSERT INTO public.posts (id,title,slug,excerpt,content,image,category_id,author,read_time,published,date,created_at,updated_at) VALUES ('06d4085e-b522-45c7-bdc2-d0c858e533dc','Comunicação não-violenta: como transformar seus relacionamentos','comunicacao-nao-violenta','Aprenda a se expressar com autenticidade sem machucar quem você ama.','<h2>O que é Comunicação Não-Violenta?</h2>
<p>Desenvolvida por Marshall Rosenberg, a CNV é uma abordagem que nos ajuda a nos conectar com os outros de forma empática e autêntica.</p>

<h3>Os 4 componentes da CNV</h3>
<p><strong>Observação:</strong> Descreva a situação sem julgamento. Em vez de "Você nunca me escuta", tente "Quando estou falando e você olha para o celular..."</p>
<p><strong>Sentimento:</strong> Identifique o que você sente. "Eu me sinto desvalorizada."</p>
<p><strong>Necessidade:</strong> Reconheça qual necessidade não está sendo atendida. "Porque preciso de atenção e conexão."</p>
<p><strong>Pedido:</strong> Faça um pedido claro e concreto. "Você poderia guardar o celular enquanto conversamos?"</p>

<h3>Na prática</h3>
<p>A CNV não é sobre ser passivo ou engolir o que sente. É sobre se expressar de forma que o outro consiga realmente ouvir.</p>

<blockquote>Quando mudamos a forma como falamos, mudamos a forma como nos relacionamos — e isso transforma tudo.</blockquote>','https://gbtobvijtqaaubftmhhl.supabase.co/storage/v1/object/public/cms-images/posts/comunicacao.jpg','c838911f-3d04-4540-b2a9-26727da10c50','Dra. Ana Silva','7 min',TRUE,'2025-04-05T00:00:00+00:00','2026-04-15T21:57:25.836978+00:00','2026-04-15T22:14:52.882481+00:00');
INSERT INTO public.posts (id,title,slug,excerpt,content,image,category_id,author,read_time,published,date,created_at,updated_at) VALUES ('7acb7fb8-9c72-4986-b940-0ed75f218875','Meditação para iniciantes: um guia gentil','meditacao-para-iniciantes','Você não precisa esvaziar a mente para meditar. Descubra como começar com compaixão.','<h2>Desmistificando a meditação</h2>
<p>A maior barreira para meditar não é a falta de tempo — é a crença de que precisamos "não pensar em nada". Isso é um mito.</p>

<h3>O que é meditar, afinal?</h3>
<p>Meditar é treinar a atenção. É perceber quando a mente viajou e, gentilmente, trazê-la de volta. Cada vez que você faz isso, está fortalecendo sua capacidade de presença.</p>

<h3>Como começar (em 5 minutos)</h3>
<ol>
<li><strong>Sente-se confortavelmente.</strong> Não precisa ser no chão. Uma cadeira serve.</li>
<li><strong>Feche os olhos</strong> e respire naturalmente.</li>
<li><strong>Observe a respiração.</strong> Sinta o ar entrando e saindo.</li>
<li><strong>Quando a mente divagar</strong> (e vai divagar), apenas note e volte à respiração.</li>
<li><strong>Não se julgue.</strong> Cada retorno é uma repetição do exercício.</li>
</ol>

<h3>Tipos de meditação para experimentar</h3>
<ul>
<li><strong>Mindfulness:</strong> Atenção ao momento presente</li>
<li><strong>Body scan:</strong> Varredura corporal, relaxando cada parte do corpo</li>
<li><strong>Meditação guiada:</strong> Ideal para iniciantes, com áudios que conduzem a prática</li>
</ul>

<blockquote>A meditação não é sobre perfeição. É sobre presença. E presença se pratica um respiro de cada vez.</blockquote>','https://gbtobvijtqaaubftmhhl.supabase.co/storage/v1/object/public/cms-images/posts/meditacao.jpg','5f224035-9731-4314-9a3b-687b2de55eac','Dra. Ana Silva','5 min',TRUE,'2025-04-02T00:00:00+00:00','2026-04-15T21:57:25.836978+00:00','2026-04-15T22:14:52.882481+00:00');
INSERT INTO public.posts (id,title,slug,excerpt,content,image,category_id,author,read_time,published,date,created_at,updated_at) VALUES ('c5563833-ea11-4d4a-90a0-f4312a5d2395','Como definir metas que realmente funcionam','como-definir-metas','Metas eficazes não são sobre força de vontade, mas sobre autocompaixão e clareza.','<h2>Além da força de vontade</h2>
<p>Todo início de ano fazemos listas de metas. E todo fevereiro, abandonamos. O problema não é falta de disciplina — é falta de conexão emocional com o objetivo.</p>

<h3>O método SMART com alma</h3>
<p>Metas eficientes são <strong>Específicas</strong>, <strong>Mensuráveis</strong>, <strong>Alcançáveis</strong>, <strong>Relevantes</strong> e com <strong>Tempo definido</strong>. Mas além disso, precisam ter significado pessoal.</p>

<h3>Perguntas que ajudam</h3>
<ul>
<li>Por que essa meta importa <em>para mim</em>?</li>
<li>Como vou me sentir quando alcançá-la?</li>
<li>Qual o menor passo que posso dar hoje?</li>
</ul>

<h3>O poder dos micro-hábitos</h3>
<p>Grandes mudanças nascem de pequenas ações consistentes. Ler uma página por dia é melhor do que planejar ler 50 livros no ano.</p>

<blockquote>A meta que funciona não é a mais ambiciosa — é aquela que conversa com quem você é e quem deseja se tornar.</blockquote>','https://gbtobvijtqaaubftmhhl.supabase.co/storage/v1/object/public/cms-images/posts/metas.jpg','26904ab5-e1aa-4088-95ef-4b3b5f0fd999','Dra. Ana Silva','6 min',TRUE,'2025-03-28T00:00:00+00:00','2026-04-15T21:57:25.836978+00:00','2026-04-15T22:14:52.882481+00:00');
INSERT INTO public.posts (id,title,slug,excerpt,content,image,category_id,author,read_time,published,date,created_at,updated_at) VALUES ('ce1a3705-ca79-47fe-b6e7-2e38e98671fd','Ansiedade: quando a preocupação vira prisão','ansiedade-quando-preocupacao-vira-prisao','Entenda a diferença entre preocupação saudável e ansiedade patológica.','<h2>Quando a preocupação se torna patológica</h2>
<p>Preocupar-se é humano. Mas quando a preocupação domina seus pensamentos, impede o sono e paralisa suas ações, ela deixou de ser saudável.</p>

<h3>Ansiedade normal vs. transtorno de ansiedade</h3>
<p>A ansiedade normal é uma resposta adaptativa — ela nos prepara para desafios. O transtorno surge quando essa resposta se ativa sem motivo real ou de forma desproporcional.</p>

<h3>Sinais de alerta</h3>
<ul>
<li>Pensamentos acelerados e repetitivos</li>
<li>Tensão muscular constante</li>
<li>Dificuldade para dormir</li>
<li>Sensação de que algo ruim vai acontecer</li>
<li>Evitação de situações cotidianas</li>
</ul>

<h3>O que fazer?</h3>
<p><strong>Respire.</strong> A respiração diafragmática ativa o sistema nervoso parassimpático, que acalma o corpo.</p>
<p><strong>Nomeie.</strong> Dizer "estou sentindo ansiedade" já diminui a intensidade da emoção.</p>
<p><strong>Busque ajuda.</strong> Um psicólogo pode ajudar você a entender e manejar a ansiedade de forma saudável.</p>

<blockquote>Sentir ansiedade não define quem você é. É apenas uma emoção — e toda emoção passa.</blockquote>','https://gbtobvijtqaaubftmhhl.supabase.co/storage/v1/object/public/cms-images/posts/ansiedade.jpg','e1b8865f-2e0c-407d-ba87-fa9721a18b9e','Dra. Ana Silva','8 min',TRUE,'2025-03-25T00:00:00+00:00','2026-04-15T21:57:25.836978+00:00','2026-04-15T22:14:52.882481+00:00');
INSERT INTO public.posts (id,title,slug,excerpt,content,image,category_id,author,read_time,published,date,created_at,updated_at) VALUES ('63dc19c2-adbe-48a0-881a-69287c2c95ef','A arte de dizer não sem culpa','a-arte-de-dizer-nao','Estabelecer limites saudáveis é um ato de respeito — consigo e com os outros.','<h2>Limites saudáveis são atos de amor</h2>
<p>Dizer não é uma das habilidades mais difíceis — e mais necessárias — para quem deseja ter relacionamentos saudáveis e uma vida equilibrada.</p>

<h3>Por que temos medo de dizer não?</h3>
<p>Desde a infância, somos condicionados a agradar. Dizer não parece egoísmo, rejeição ou abandono. Mas na verdade, é uma forma de <strong>honrar suas necessidades</strong>.</p>

<h3>Como dizer não sem culpa</h3>
<ol>
<li><strong>Reconheça seu limite.</strong> Se algo não cabe na sua vida agora, tudo bem.</li>
<li><strong>Seja direto e gentil.</strong> "Agradeço o convite, mas não consigo dessa vez."</li>
<li><strong>Não se justifique demais.</strong> Seu não não precisa de um parágrafo de explicação.</li>
<li><strong>Pratique.</strong> Comece com situações pequenas e vá fortalecendo esse músculo.</li>
</ol>

<h3>O que acontece quando você aprende a dizer não</h3>
<p>Você ganha tempo, energia e respeito — dos outros e de si mesmo. Seus "sins" passam a ser mais genuínos e presentes.</p>

<blockquote>Dizer não para o que te esgota é dizer sim para o que te nutre.</blockquote>','https://gbtobvijtqaaubftmhhl.supabase.co/storage/v1/object/public/cms-images/posts/dizer-nao.jpg','c838911f-3d04-4540-b2a9-26727da10c50','Dra. Ana Silva','5 min',TRUE,'2025-03-20T00:00:00+00:00','2026-04-15T21:57:25.836978+00:00','2026-04-15T22:14:52.882481+00:00');
INSERT INTO public.posts (id,title,slug,excerpt,content,image,category_id,author,read_time,published,date,created_at,updated_at) VALUES ('e9c4c9b9-e3f6-4f5a-baa4-460b7199d275','Gratidão como prática diária: além do clichê','gratidao-como-pratica-diaria','A ciência por trás da gratidão e como ela pode rewire seu cérebro para o bem-estar.','<h2>Mais do que uma lista de "coisas boas"</h2>
<p>A gratidão virou clichê de redes sociais. Mas quando praticada com intenção e profundidade, ela é uma das ferramentas mais poderosas de bem-estar emocional.</p>

<h3>O que a ciência diz</h3>
<p>Estudos de Robert Emmons mostram que pessoas que praticam gratidão regularmente apresentam:</p>
<ul>
<li>Menos sintomas de depressão</li>
<li>Melhor qualidade de sono</li>
<li>Maior resiliência emocional</li>
<li>Relacionamentos mais satisfatórios</li>
</ul>

<h3>Como praticar de verdade</h3>
<p><strong>Seja específico.</strong> Em vez de "sou grata pela minha família", tente "sou grata pela conversa que tive com minha mãe hoje à tarde".</p>
<p><strong>Sinta no corpo.</strong> Não basta escrever — permita-se sentir a gratidão. Onde ela aparece no seu corpo?</p>
<p><strong>Inclua os desafios.</strong> Agradecer também pelos momentos difíceis que trouxeram aprendizado é um nível mais profundo de prática.</p>

<blockquote>Gratidão não é negar a dor. É reconhecer que, mesmo em meio a ela, existe algo que sustenta você.</blockquote>','https://gbtobvijtqaaubftmhhl.supabase.co/storage/v1/object/public/cms-images/posts/gratidao.jpg','5f224035-9731-4314-9a3b-687b2de55eac','Dra. Ana Silva','6 min',TRUE,'2025-03-15T00:00:00+00:00','2026-04-15T21:57:25.836978+00:00','2026-04-15T22:14:52.882481+00:00');
INSERT INTO public.posts (id,title,slug,excerpt,content,image,category_id,author,read_time,published,date,created_at,updated_at) VALUES ('dd328f27-43ea-4620-8ea7-5fed8226fc6e','Síndrome do impostor: por que você duvida de si mesmo','sindrome-do-impostor','Descubra por que pessoas competentes se sentem fraudes — e como superar isso.','<h2>O medo de ser "descoberto"</h2>
<p>Você já conquistou algo importante e, em vez de comemorar, pensou: "Logo vão perceber que não sou tão bom assim"? Isso tem nome — e é mais comum do que você imagina.</p>

<h3>O que é a síndrome do impostor?</h3>
<p>É um padrão psicológico onde a pessoa duvida de suas conquistas e tem medo de ser exposta como "fraude", mesmo tendo evidências claras de competência.</p>

<h3>Quem é afetado?</h3>
<p>Pesquisas indicam que até <strong>70% das pessoas</strong> experimentam esse sentimento em algum momento da vida. É especialmente comum em:</p>
<ul>
<li>Pessoas em início de carreira</li>
<li>Profissionais em posições de destaque</li>
<li>Estudantes de pós-graduação</li>
<li>Minorias em ambientes não diversos</li>
</ul>

<h3>Como lidar</h3>
<p><strong>Normalize.</strong> Saber que isso é comum já alivia parte da angústia.</p>
<p><strong>Registre suas conquistas.</strong> Tenha uma lista visível do que você já realizou.</p>
<p><strong>Compartilhe.</strong> Falar sobre esse sentimento com pessoas de confiança quebra o isolamento.</p>
<p><strong>Diferencie sentimento de fato.</strong> Sentir que é uma fraude não significa que você é uma.</p>

<blockquote>Você não está fingindo. Você está aprendendo. E aprender é o que pessoas competentes fazem.</blockquote>','https://gbtobvijtqaaubftmhhl.supabase.co/storage/v1/object/public/cms-images/posts/impostor.jpg','26904ab5-e1aa-4088-95ef-4b3b5f0fd999','Dra. Ana Silva','7 min',TRUE,'2025-03-10T00:00:00+00:00','2026-04-15T21:57:25.836978+00:00','2026-04-15T22:14:52.882481+00:00');
INSERT INTO public.posts (id,title,slug,excerpt,content,image,category_id,author,read_time,published,date,created_at,updated_at) VALUES ('ff9c71ae-dcf2-485c-acaf-20db3dbbc9a6','Como cultivar relacionamentos saudáveis na era digital','relacionamentos-era-digital','A tecnologia nos conecta e nos afasta ao mesmo tempo. Como encontrar o equilíbrio?','<h2>Conexão real em tempos de tela</h2>
<p>Nunca estivemos tão conectados tecnologicamente — e tão desconectados emocionalmente. A era digital trouxe facilidades, mas também novos desafios para os relacionamentos.</p>

<h3>Os desafios digitais</h3>
<p><strong>Comparação constante.</strong> Redes sociais mostram recortes editados da vida dos outros, gerando insatisfação com nossos próprios relacionamentos.</p>
<p><strong>Comunicação superficial.</strong> Emojis e mensagens curtas nem sempre transmitem o que realmente sentimos.</p>
<p><strong>Disponibilidade excessiva.</strong> A expectativa de respostas imediatas gera ansiedade e conflitos.</p>

<h3>Como cultivar conexões mais profundas</h3>
<ol>
<li><strong>Priorize o presencial.</strong> Sempre que possível, escolha o encontro real.</li>
<li><strong>Pratique a escuta ativa.</strong> Guarde o celular e esteja presente na conversa.</li>
<li><strong>Estabeleça limites digitais.</strong> Horários sem tela fortalecem a intimidade.</li>
<li><strong>Use a tecnologia a seu favor.</strong> Videochamadas e mensagens de voz podem ser mais calorosas que textos.</li>
</ol>

<blockquote>A qualidade de um relacionamento não se mede pelo número de mensagens trocadas, mas pela profundidade do que é compartilhado.</blockquote>','https://gbtobvijtqaaubftmhhl.supabase.co/storage/v1/object/public/cms-images/posts/relacionamentos-digital.jpg','c838911f-3d04-4540-b2a9-26727da10c50','Dra. Ana Silva','8 min',TRUE,'2025-03-05T00:00:00+00:00','2026-04-15T21:57:25.836978+00:00','2026-04-15T22:14:52.882481+00:00');
INSERT INTO public.site_content (id,section_key,content,created_at,updated_at) VALUES ('8550092f-c8db-4b06-ac1a-c150f87baef2','hero','{"title":"Psicologia para a vida real","subtitle":"Reflexões, acolhimento e ferramentas para sua jornada interior","description":"Um espaço dedicado a tornar a psicologia acessível, humana e transformadora. Aqui você encontra conteúdos que conectam ciência e sensibilidade.","image_mobile":"","image_desktop":""}'::jsonb,'2026-03-12T11:07:20.228392+00:00','2026-04-15T21:57:46.404721+00:00');
INSERT INTO public.site_content (id,section_key,content,created_at,updated_at) VALUES ('41199364-c3bc-4b3e-b571-0cf967e67523','about_preview','{"quote":"Cuidar da mente é o ato mais revolucionário que existe.","title":"Sobre o Projeto","description":"O PsiconaVida nasceu da crença de que a psicologia não deveria ficar restrita aos consultórios. Nosso objetivo é levar conhecimento emocional para o dia a dia, com linguagem acessível e embasamento científico.","image_author":"","image_secondary":""}'::jsonb,'2026-03-12T11:07:20.228392+00:00','2026-04-15T21:57:46.404721+00:00');
INSERT INTO public.site_content (id,section_key,content,created_at,updated_at) VALUES ('9bb90ac0-e926-47ee-8405-d053329b4dfb','manifesto','{"lines":["Acreditamos que toda pessoa merece ser ouvida.","Que a saúde mental não é luxo, é direito.","Que vulnerabilidade é força, não fraqueza.","Que o autoconhecimento transforma vidas.","Que a psicologia pertence a todos.","Que acolher é o primeiro passo para curar.","Que cada pequena mudança gera grandes revoluções internas."],"title":"Nosso Manifesto"}'::jsonb,'2026-03-12T11:07:20.228392+00:00','2026-04-15T21:57:46.404721+00:00');
INSERT INTO public.site_content (id,section_key,content,created_at,updated_at) VALUES ('af942d3f-531c-4311-a5cc-e8ad6b325a51','newsletter','{"image":"","title":"Receba reflexões no seu e-mail","button_url":"#","button_text":"Quero receber","description":"Toda semana, um conteúdo especial sobre saúde mental, autoconhecimento e bem-estar emocional — direto na sua caixa de entrada.","footer_text":"Sem spam. Apenas acolhimento."}'::jsonb,'2026-03-12T11:07:20.228392+00:00','2026-04-15T21:57:46.404721+00:00');
INSERT INTO public.site_content (id,section_key,content,created_at,updated_at) VALUES ('5990d107-7acf-4411-b8cd-f196a7a9a0f7','ethical_notice','{"text":"Este blog tem caráter informativo e educacional. Os conteúdos aqui apresentados não substituem acompanhamento psicológico ou psiquiátrico profissional. Se você está em sofrimento, procure ajuda especializada. CVV: 188 (24h)."}'::jsonb,'2026-03-12T11:07:20.228392+00:00','2026-04-15T21:57:46.404721+00:00');
INSERT INTO public.site_content (id,section_key,content,created_at,updated_at) VALUES ('7459923c-43f0-4e5f-8859-601ee45a0c90','about_page','{"intro":"O PsiconaVida é um projeto que nasceu do desejo de democratizar o acesso ao conhecimento sobre saúde mental e bem-estar emocional. Acreditamos que a psicologia não deveria ser um privilégio, mas uma ferramenta disponível para todos.","title":"Sobre o PsiconaVida","subtitle":"Psicologia acessível para todos","author_bio":"Psicóloga clínica com mais de 10 anos de experiência, especialista em Terapia Cognitivo-Comportamental e apaixonada por tornar a psicologia acessível. Criadora do PsiconaVida, escreve sobre autoconhecimento, saúde mental e desenvolvimento pessoal com uma abordagem acolhedora e baseada em evidências.","author_name":"Dra. Ana Silva","author_image":"","mission_text":"Tornar a psicologia acessível, humana e transformadora. Queremos que cada pessoa que chegue aqui se sinta acolhida, compreendida e inspirada a cuidar de si mesma com mais gentileza e consciência.","mission_title":"Nossa Missão"}'::jsonb,'2026-03-12T11:07:20.228392+00:00','2026-04-15T21:57:46.404721+00:00');